'use client';
import { useState, useEffect } from 'react';
import { listMaterials, createMaterial, deleteMaterial } from '@/lib/api';

export default function MaterialsPage() {
  const [materials, setMaterials] = useState<any[]>([]);
  const [projectId, setProjectId] = useState(1);
  const [filename, setFilename] = useState('');
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    loadMaterials();
  }, [projectId]);

  async function loadMaterials() {
    const data = await listMaterials(projectId);
    setMaterials(data);
  }

  async function handleCreate(e: React.FormEvent) {
    e.preventDefault();
    setLoading(true);
    try {
      await createMaterial({
        project_id: projectId,
        source_type: 'upload',
        media_type: 'document',
        storage_path: `/uploads/${filename}`,
        filename
      });
      setFilename('');
      await loadMaterials();
    } finally {
      setLoading(false);
    }
  }

  async function handleDelete(id: number) {
    if (confirm('确定删除？')) {
      await deleteMaterial(id);
      await loadMaterials();
    }
  }

  return (
    <main style={{ padding: '2rem' }}>
      <h1>案件材料管理</h1>

      <form onSubmit={handleCreate} style={{ marginTop: '1rem', display: 'flex', gap: '0.5rem' }}>
        <input
          type="number"
          value={projectId}
          onChange={e => setProjectId(Number(e.target.value))}
          placeholder="项目ID"
          style={{ width: '100px' }}
        />
        <input
          type="text"
          value={filename}
          onChange={e => setFilename(e.target.value)}
          placeholder="文件名"
          required
          style={{ flex: 1 }}
        />
        <button type="submit" disabled={loading}>添加材料</button>
      </form>

      <div style={{ marginTop: '2rem' }}>
        <h2>材料列表</h2>
        {materials.length === 0 ? (
          <p>暂无材料</p>
        ) : (
          <ul>
            {materials.map(m => (
              <li key={m.id} style={{ marginBottom: '0.5rem' }}>
                {m.filename} ({m.media_type})
                <button onClick={() => handleDelete(m.id)} style={{ marginLeft: '1rem' }}>删除</button>
              </li>
            ))}
          </ul>
        )}
      </div>
    </main>
  );
}

